const { execSync } = require('child_process');
const fs = require('fs');

try {
  // Read env from the container's environment file
  let envVars = {};
  try {
    const procEnv = fs.readFileSync('/proc/1/environ', 'utf-8');
    procEnv.split('\0').forEach(line => {
      const eq = line.indexOf('=');
      if (eq > 0) envVars[line.substring(0, eq)] = line.substring(eq + 1);
    });
  } catch(e) {
    return [{ json: { vms: [], error: 'Cannot read container environment: ' + e.message } }];
  }

  const url = envVars.PROXMOX_URL;
  const node = envVars.PROXMOX_NODE;
  const tokenId = envVars.PROXMOX_TOKEN_ID;
  const tokenSecret = envVars.PROXMOX_TOKEN_SECRET;

  if (!url) return [{ json: { vms: [], error: 'PROXMOX_URL not configured in .env' } }];

  const fetchScript = 'const https=require("https");https.get("' + url + '/api2/json/nodes/' + node + '/qemu",{headers:{"Authorization":"PVEAPIToken=' + tokenId + '=' + tokenSecret + '"},rejectUnauthorized:false},res=>{let d="";res.on("data",c=>d+=c);res.on("end",()=>console.log(d))}).on("error",e=>console.log(JSON.stringify({error:e.message})));';

  const raw = execSync('node -e \'' + fetchScript + '\'', { encoding: 'utf-8', timeout: 15000 });
  const data = JSON.parse(raw);

  if (data.error) return [{ json: { vms: [], error: data.error } }];

  const vms = (data.data || [])
    .filter(vm => vm.vmid >= 200 && vm.vmid < 300)
    .map(vm => ({
      vmid: vm.vmid,
      name: vm.name || 'vm-' + vm.vmid,
      status: vm.status,
      ip: null,
      uptime: vm.uptime || 0,
      tags: vm.tags || ''
    }));

  return [{ json: { vms } }];
} catch(e) {
  return [{ json: { vms: [], error: e.message } }];
}

const { execSync } = require('child_process');
const vmid = $input.first().json.params?.vmid || $input.first().json.body?.vmid;
if (!vmid) return [{ json: { success: false, error: 'No vmid provided' } }];

try {
  const url = process.env.PROXMOX_URL + '/api2/json/nodes/' + process.env.PROXMOX_NODE + '/qemu/' + vmid + '/status/start';
  const auth = 'PVEAPIToken=' + process.env.PROXMOX_TOKEN_ID + '=' + process.env.PROXMOX_TOKEN_SECRET;
  const script = `const https=require('https');const u=new URL('${url}');const req=https.request({hostname:u.hostname,port:u.port,path:u.pathname,method:'POST',headers:{'Authorization':'${auth}'},rejectUnauthorized:false},res=>{let d='';res.on('data',c=>d+=c);res.on('end',()=>console.log(JSON.stringify({status:res.statusCode})))});req.end();`;
  const raw = execSync('node -e "' + script.replace(/"/g, '\\\\"') + '"', { encoding: 'utf-8', timeout: 15000 });
  return [{ json: { success: true, action: 'start_vm', vmid: vmid } }];
} catch(e) {
  return [{ json: { success: false, error: e.message } }];
}

